// Validate and unpack incoming payload
const body = $input.first().json.body || $input.first().json;

if (!body.jobId)       throw new Error('jobId is required');
if (!body.issueKey)    throw new Error('issueKey is required');
if (!body.workflow)    throw new Error('workflow definition is required');
if (!body.callbackUrl) throw new Error('callbackUrl is required');

const { jobId, issueKey, workflow, repo, settings, callbackUrl } = body;

return [{
  json: {
    jobId,
    issueKey,
    workflow,
    repo: repo || {},
    settings: settings || {},
    callbackUrl,
    stepResults: {},
  },
}];

// Helper: POST a step-level status update back to the local callback server
async function postCallback(callbackUrl, jobId, stepId, status, message) {
  try {
    await fetch(callbackUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ jobId, stepId, status, message }),
    });
  } catch (e) {
    console.error('[auto-code] Callback failed:', e.message);
  }
}

const { jobId, issueKey, workflow, repo, settings, callbackUrl } = $json;
const steps = Array.isArray(workflow.steps) ? workflow.steps : [];
const basicAuth = settings.jiraEmail && settings.jiraToken
  ? 'Basic ' + Buffer.from(settings.jiraEmail + ':' + settings.jiraToken).toString('base64')
  : '';

const SYSTEM_PROMPT = `You are a senior software engineer. Return only valid JSON — no markdown, no explanation.`;

// Accumulated context carried between steps
const context = {
  issueKey,
  repo,
  settings,
  jiraSummary: '',
  jiraDescription: '',
  analysisResult: '',
  generatedCode: null,  // { summary, files, patch }
};

// ── Step executor ───────────────────────────────────────────────────────────
async function executeStep(step, ctx) {
  const type   = step.type || 'CUSTOM';
  const config = step.config || {};

  switch (type) {

    // ── FETCH_JIRA — load issue from Jira API ──────────────────────────────
    case 'FETCH_JIRA': {
      if (!settings.jiraUrl || !basicAuth) {
        return { ok: false, message: 'Jira credentials not configured' };
      }
      const res = await fetch(
        `${settings.jiraUrl}/rest/api/3/issue/${issueKey}?fields=summary,description,issuetype,status,comment`,
        { headers: { Authorization: basicAuth, Accept: 'application/json' } }
      );
      if (!res.ok) throw new Error(`Jira API error ${res.status}`);
      const data = await res.json();
      ctx.jiraSummary     = data.fields?.summary || '';
      ctx.jiraDescription = JSON.stringify(data.fields?.description || '');
      return { ok: true, message: `Fetched: ${ctx.jiraSummary}` };
    }

    // ── AI_ANALYZE — analyze issue / codebase ──────────────────────────────
    case 'AI_ANALYZE': {
      const prompt = [
        config.promptTemplate || 'Analyze the following Jira issue and provide a technical analysis.',
        '',
        `Issue: ${ctx.jiraSummary}`,
        `Description: ${ctx.jiraDescription.slice(0, 2000)}`,
        '',
        'Return JSON: { "analysis": "<string>", "affectedFiles": ["<path>"], "approach": "<string>" }',
      ].join('\n');
      const aiRes = await callAI(settings, prompt, SYSTEM_PROMPT, config.maxTokens || 4096);
      ctx.analysisResult = aiRes;
      return { ok: true, message: 'Analysis complete' };
    }

    // ── AI_GENERATE — generate code ────────────────────────────────────────
    case 'AI_GENERATE': {
      const lang = settings.language || 'javascript';
      const prompt = [
        config.promptTemplate || `You are a senior ${lang} developer. Generate production-ready code.`,
        '',
        `Issue: ${ctx.jiraSummary}`,
        `Description: ${ctx.jiraDescription.slice(0, 2000)}`,
        ctx.analysisResult ? `Analysis:\n${ctx.analysisResult}` : '',
        '',
        'Return ONLY valid JSON with keys: "summary" (string), "files" (array of {name, content}), "patch" (string unified diff).',
      ].filter(Boolean).join('\n');
      const raw = await callAI(settings, prompt, SYSTEM_PROMPT, config.maxTokens || 8192);
      const cleaned = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/, '').trim();
      ctx.generatedCode = JSON.parse(cleaned);
      return { ok: true, message: `Generated ${ctx.generatedCode.files?.length || 0} file(s)` };
    }

    // ── APPLY_PATCH — call app callback to trigger patch apply ────────────
    case 'APPLY_PATCH': {
      if (!ctx.generatedCode?.patch) return { ok: true, message: 'No patch to apply' };
      // Signal the app to apply the patch via the job result
      // The app will handle the actual file application after job completes
      return { ok: true, message: 'Patch ready for application' };
    }

    // ── GIT_STATUS — check git status ─────────────────────────────────────
    case 'GIT_STATUS': {
      return { ok: true, message: 'Git status check complete (handled by app)' };
    }

    // ── GIT_COMMIT — signal app to commit ────────────────────────────────
    case 'GIT_COMMIT': {
      const msg = (config.message || 'feat: {{issueKey}} - {{summary}}')
        .replace('{{issueKey}}', issueKey)
        .replace('{{summary}}', ctx.jiraSummary);
      return { ok: true, message: `Commit message: ${msg}` };
    }

    // ── CUSTOM — fire a custom HTTP endpoint ──────────────────────────────
    case 'CUSTOM': {
      if (!config.url) return { ok: false, message: 'No URL configured for CUSTOM step' };
      const method = (config.method || 'POST').toUpperCase();
      const res = await fetch(config.url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        ...(method !== 'GET' ? { body: JSON.stringify({ jobId, issueKey, context: ctx }) } : {}),
      });
      if (!res.ok) throw new Error(`Custom endpoint returned ${res.status}`);
      return { ok: true, message: `Custom step responded ${res.status}` };
    }

    default:
      return { ok: false, message: `Unknown step type: ${type}` };
  }
}

// ── AI provider router ───────────────────────────────────────────────────────
async function callAI(settings, userPrompt, systemPrompt, maxTokens) {
  const { provider, model, openaiKey, claudeKey, geminiKey } = settings;

  if (provider === 'claude') {
    const res = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: { 'x-api-key': claudeKey, 'anthropic-version': '2023-06-01', 'Content-Type': 'application/json' },
      body: JSON.stringify({ model: model || 'claude-3-5-sonnet-20241022', max_tokens: maxTokens, system: systemPrompt, messages: [{ role: 'user', content: userPrompt }] }),
    });
    if (!res.ok) throw new Error(`Claude API error ${res.status}: ${await res.text()}`);
    const data = await res.json();
    return data.content[0].text;
  }

  if (provider === 'gemini') {
    const mdl = model || 'gemini-1.5-pro';
    const res = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/${mdl}:generateContent?key=${geminiKey}`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ contents: [{ parts: [{ text: `${systemPrompt}\n\n${userPrompt}` }] }], generationConfig: { temperature: 0.2, maxOutputTokens: maxTokens } }),
    });
    if (!res.ok) throw new Error(`Gemini API error ${res.status}: ${await res.text()}`);
    const data = await res.json();
    return data.candidates[0].content.parts[0].text;
  }

  // Default: OpenAI
  const res = await fetch('https://api.openai.com/v1/chat/completions', {
    method: 'POST',
    headers: { 'Authorization': `Bearer ${openaiKey}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({ model: model || 'gpt-4o', temperature: 0.2, max_tokens: maxTokens, messages: [{ role: 'system', content: systemPrompt }, { role: 'user', content: userPrompt }] }),
  });
  if (!res.ok) throw new Error(`OpenAI API error ${res.status}: ${await res.text()}`);
  const data = await res.json();
  return data.choices[0].message.content;
}

// ── Execute all steps sequentially ──────────────────────────────────────────
const stepResults = {};

for (const step of steps) {
  // Notify: step is starting
  await postCallback(callbackUrl, jobId, step.id, 'running', `Starting: ${step.label}`);

  try {
    const result = await executeStep(step, context);
    stepResults[step.id] = { ...result, status: result.ok ? 'done' : 'failed' };

    // Notify: step result
    await postCallback(
      callbackUrl, jobId, step.id,
      result.ok ? 'done' : 'failed',
      result.message || ''
    );

    if (!result.ok) {
      // Hard stop on failure
      await postCallback(callbackUrl, jobId, null, 'FAILED', `Step failed: ${step.label} — ${result.message}`);
      return [{ json: { jobId, status: 'FAILED', stepResults, context } }];
    }
  } catch (err) {
    stepResults[step.id] = { ok: false, status: 'failed', message: err.message };
    await postCallback(callbackUrl, jobId, step.id, 'failed', err.message);
    await postCallback(callbackUrl, jobId, null, 'FAILED', `Uncaught error in step ${step.label}: ${err.message}`);
    return [{ json: { jobId, status: 'FAILED', stepResults, error: err.message, context } }];
  }
}

// All steps done — signal completion
await postCallback(callbackUrl, jobId, null, 'DONE', 'All steps completed successfully');

return [{ json: { jobId, status: 'DONE', stepResults, generatedCode: context.generatedCode } }];
